
// ── Typing animation ──
const roles = ['Full Stack Developer', 'Python & Django Developer', 'Backend Developer', 'REST API Developer'];
let ri = 0, ci = 0, del = false;
const el = document.getElementById('typed');
function type() {
    const w = roles[ri];
    if (!del) { el.textContent = w.slice(0, ++ci); if (ci === w.length) { del = true; setTimeout(type, 1800); return } }
    else { el.textContent = w.slice(0, --ci); if (ci === 0) { del = false; ri = (ri + 1) % roles.length } }
    setTimeout(type, del ? 55 : 95);
}
type();

// ── Project 1 slideshow ──
const p1imgs = ["data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,"];
const p1lbls = ["Citizen Dashboard", "Apply for Passport", "Review & Submit", "My Profile", "Progress Timeline", "Notifications", "ML Analytics", "Officer Portal"];
let p1i = 0;
function p1go(i) {
    p1i = i;
    document.getElementById('p1-img').src = p1imgs[i];
    document.querySelectorAll('#p1-dots .ss-dot').forEach((d, idx) => d.classList.toggle('active', idx === i));
}
function p1slide(dir) { p1go((p1i + dir + 8) % 8) }
setInterval(() => p1slide(1), 3800);


// ── Theme Toggle ──
function toggleTheme() {
    document.body.classList.toggle('light-mode');
    const btn = document.getElementById('theme-btn');
    btn.textContent = document.body.classList.contains('light-mode') ? '☀️' : '🌙';
    localStorage.setItem('theme', document.body.classList.contains('light-mode') ? 'light' : 'dark');
}
// Load saved theme
if (localStorage.getItem('theme') === 'light') {
    document.body.classList.add('light-mode');
    document.getElementById('theme-btn').textContent = '☀️';
}

// ── Counter animation ──
function animCount(el, target, duration = 1500) {
    let start = 0, step = target / 60;
    const timer = setInterval(() => {
        start = Math.min(start + step, target);
        el.textContent = Math.floor(start);
        if (start >= target) clearInterval(timer);
    }, duration / 60);
}

// ── GitHub API fetch ──
async function fetchGitHub() {
    try {
        const res = await fetch('https://api.github.com/users/Jayhind-Yadav592');
        const data = await res.json();
        if (data.public_repos !== undefined) {
            animCount(document.getElementById('repo-count'), data.public_repos);
            animCount(document.getElementById('follower-count'), data.followers);
        }
    } catch (e) {
        // Fallback values
        animCount(document.getElementById('repo-count'), 8);
        animCount(document.getElementById('follower-count'), 3);
    }
    // These are static/estimated
    animCount(document.getElementById('contrib-count'), 120);
    animCount(document.getElementById('lc-count'), 170);
    animCount(document.getElementById('commit-count'), 95);
    animCount(document.getElementById('proj-count'), 48);
    document.getElementById('contrib-sub').textContent = '120+ contributions this year';
}

// Run when github-stats section is visible
const observer = new IntersectionObserver((entries) => {
    entries.forEach(e => {
        if (e.isIntersecting) {
            fetchGitHub();
            observer.disconnect();
        }
    });
}, { threshold: 0.2 });
const gsSection = document.getElementById('github-stats');
if (gsSection) observer.observe(gsSection);


// ICoder images
const p2imgs = ["data:image/png;base64,", "data:image/png;base64,", "data:image/png;base64,", "data:image/png;base64,", "data:image/png;base64,"];
const p2lbls = ["Home Page", "Blog Posts", "Blog Detail", "About Page", "Contact Page"];
let p2i = 0;
function p2go(i) {
    p2i = i;
    const img = document.getElementById('p2-img');
    if (img) img.src = p2imgs[i];
    document.querySelectorAll('#p2-dots .ss-dot').forEach((d, idx) => d.classList.toggle('active', idx === i));
}
function p2slide(dir) { p2go((p2i + dir + 5) % 5); }
setInterval(() => p2slide(1), 4200);

// ── Active nav on scroll ──
window.addEventListener('scroll', () => {
    const secs = ['home', 'projects', 'skills', 'about', 'certificates', 'contact'];
    let cur = 'home';
    secs.forEach(id => { const s = document.getElementById(id); if (s && window.scrollY >= s.offsetTop - 140) cur = id; });
    document.querySelectorAll('.nav-pills a').forEach(a => {
        a.classList.toggle('active', a.getAttribute('href') === '#' + cur);
    });
});
